import sys
def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it))
        # read matrix but we only need diagonal values
        diag = []
        for i in range(N):
            for j in range(N):
                val = int(next(it))
                if i == j:
                    diag.append(val)
        ans = 0
        for i in range(N-1, -1, -1):
            target = i * N + (i + 1)
            if diag[i] != target:
                ans += 1
        out.append(str(ans))
    sys.stdout.write('\n'.join(out))
if __name__ == "__main__":
    solve()

