const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let idx = 0;
if (input.length === 0) process.exit(0);
const T = Number(input[idx++]);
let out = [];
for (let t = 0; t < T; t++) {
  const N = Number(input[idx++]);
  const diag = new Array(N);
  for (let i = 0; i < N; i++) {
    for (let j = 0; j < N; j++) {
      const val = Number(input[idx++]);
      if (i === j) diag[i] = val;
    }
  }
  let ans = 0;
  for (let i = N - 1; i >= 0; i--) {
    const target = i * N + (i + 1);
    if (diag[i] !== target) ans++;
  }
  out.push(String(ans));
}
